import math

def is_prime(n):
  """Checks if a number is prime."""
  if not isinstance(n, int):
      raise TypeError("Input must be an integer.")

  if n <= 1:
    return False # Numbers less than or equal to 1 are not prime
  if n <= 3:
    return True  # 2 and 3 are prime
  if n % 2 == 0 or n % 3 == 0:
    return False # Eliminate multiples of 2 and 3 early

  # Check factors from 5 upwards, stepping by 6 (optimisation)
  # Only need to check up to the integer square root of n
  # Use math.isqrt for integer square root (Python 3.8+)
  # For older Python, use int(math.sqrt(n))
  limit = math.isqrt(n)
  i = 5
  while i <= limit:
    if n % i == 0 or n % (i + 2) == 0:
      return False
    i += 6

  return True # If no divisors found, it's prime

# Example usage
numbers_to_check = [0, 1, 2, 3, 4, 17, 25, 29, 97, 100, -5]

for num in numbers_to_check:
  if is_prime(num):
    print(f"{num} is a prime number.")
  else:
    print(f"{num} is not a prime number.")
